== TemplateData ==
{{TemplateData header}}
<templatedata>{
	"description": "It is to change the font size of a text string. Two forms {{resize|<size>|<text>}} and {{resize|<text>}} are possible.",
	"params": {
		"1": {
			"label": "Size/Text",
			"description": "With two parameters: a CSS font size e.g. '80%', '1.2em', 'x-large', 'larger'. With one parameter: the text to display (and font size defaults to '90%').",
			"type": "string",
			"required": true
		},
		"2": {
			"label": "Text when size is given",
			"description": "The text to display in the two parameter version.",
			"type": "string",
			"required": false
		},
		"div": {
			"label": "Use div tag",
			"description": "Set to yes to use a div instead of a span tag.",
			"type": "string",
			"required": false
		},
		"size": {
			"label": "Size (percent)",
			"description": "Font size as a percentage e.g. '90', '200'. Ignored if 2 numbered parameters are used."
		}
	},
	"paramOrder": [
		"1",
		"2",
		"div",
		"size"
	]
}
</templatedata>

